example.code:
# GOOD: Initialize outside handler (runs once per container) import boto3
dynamodb = boto3.resource('dynamodb') table = dynamodb.Table('orders')
def handler(event, context): # Reuses existing connection — no TLS handshake, no auth on warm invocations return table.get_item(Key={'id': event['id']})

# BAD: Initialize inside handler (runs every invocation)
def handler(event, context):
    import boto3  # Import overhead on every call!
    dynamodb = boto3.resource('dynamodb')  # TLS + auth on every call!
    table = dynamodb.Table('orders')
    return table.get_item(Key={'id': event['id']})
